-- 总费用与 预算费用差异率测算

UPDATE `object_validations` SET `trigger_code`='from django.db import connection\nspeaker_expense = 0\ntotal_expense = round(sum(instance.event.eventexpenses_set.filter(deleted=0, total_expense__isnull=False).values_list(\'total_expense\', flat=True)))\n# speaker_expense = round(sum(instance.event.eventspeakers_set.filter(deleted=0, speaker_expense__isnull=False).values_list(\n#     \'speaker_expense\', flat=True)))\nexpenses =total_expense\nif (instance.event.state.name == u\'save\'or instance.event.state.name == u\'rejected\'):\n    with connection.cursor() as c:\n        sql = \'update events set text_5 = %s where id = %s\'\n        c.execute(sql, (expenses, instance.event.id))\n\n        sql2 = \"update events set text_6 =concat(truncate(ABS({0} - event_budget)/event_budget *100,2),\'%\') where id = {1}\".format(\n            expenses, instance.event.id)\n        c.execute(sql2)' WHERE `id`='h0052552-e0e1-11e8-b6c8-02f90e0f46f3';
UPDATE `object_validations` SET `description`='活动更新时更新总费用总预算', `trigger_code`='from django.db import connection\n# speaker_expense = 0\ntotal_expense = round(sum(instance.eventexpenses_set.filter(deleted=0, total_expense__isnull=False).values_list(\'total_expense\', flat=True)))\n# speaker_expense = round(sum(instance.eventspeakers_set.filter(deleted=0, speaker_expense__isnull=False).values_list(\n#     \'speaker_expense\', flat=True)))\nexpenses =total_expense\nif (instance.state.name == u\'save\'or instance.state.name == u\'rejected\'):\n    with connection.cursor() as c1:\n        sql = \'update events set text_5 = %s where id = %s\'\n        c1.execute(sql, (expenses, instance.id))\n\n        sql2 = \"update events set text_6 =concat(truncate(ABS({0} - event_budget)/event_budget *100,2),\'%\') where id = {1}\".format(\n            expenses, instance.id)\n        c1.execute(sql2)' WHERE `id`='i0052552-e0e1-11e8-b6c8-02f90e0f46f4';

