INSERT INTO `role_to_object_permissions` (`id`, `role_id`, `object_id`, `allow_read`, `allow_create`, `allow_update`, `allow_delete`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `allow_import`, `allow_export`, `allow_read_all`, `allow_update_all`, `allow_update_attachment`) VALUES ('73b750fe-ec04-11e9-b9aa-0298a739dec0', '53de9670-1da3-11e6-961c-5cc5d4b57135', '66036d1a-4643-49d5-b21a-0db9d60b0563', '1', '1', '1', '1', '0', '1', '2019-10-11 02:19:33', '1', '2019-10-11 02:19:33', '0', '0', '1', '1', '0');
