INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`) VALUES ('e49b1287-ec01-11e9-b9aa-0298a739dec0', '66036d1a-4643-49d5-b21a-0db9d60b0563', '测算参会人员数量', '测算参会人员数量', 'trigger', 'from django.db import connection\n\nwith connection.cursor() as cursor:\n    # 提交报告时测算字段\n    sql = \"\"\"\n            select count(id) from event_accounts where event_id = %s and deleted = 0 and record_type_id = \'c1491afa-18f4-4046-8e25-b62aed90eb77\'\n            \"\"\"\n    cursor.execute(sql, (instance.event.id,))\n    rows = cursor.fetchone()\n    if rows:\n        num_1 = rows[0]\n    else:\n        num_1 = 0\n    sql = \'update events set text_3 = %s where id = %s\'\n    cursor.execute(sql, (num_1, instance.event.id))', '', '0', '1', '2019-10-11 09:52:34', '1', '2019-10-11 08:48:47', 'post_save', '1', 'custom', 'attendee_num');
INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('h0052552-e0e1-11e8-b6c8-02f90e0f46f3', '87d3c319-598a-4fe2-b391-21b8bbcae4c7', '费用更新时更新总费用总预算', '费用更新时更新总费用总预算', 'trigger', 'from django.db import connection\nspeaker_expense = 0\ntotal_expense = round(sum(instance.event.eventexpenses_set.filter(deleted=0, total_expense__isnull=False,\n                 speaker_id__isnull=True).values_list(\'total_expense\', flat=True)))\n\nspeaker_expense = round(sum(instance.event.eventspeakers_set.filter(deleted=0, speaker_expense__isnull=False).values_list(\n    \'speaker_expense\', flat=True)))\n\nexpenses =total_expense + speaker_expense\n\nif (instance.event.state.name == u\'save\'or instance.event.state.name == u\'rejected\') and \\\n    not instance.event.record_type.name.endswith(\'__report\'):\n    with connection.cursor() as c:\n        sql = \'update events set event_budget = %s where id = %s\'\n        c.execute(sql, (expenses, instance.event.id))\nelif (instance.event.state.name == u\'save\'or instance.event.state.name == u\'rejected\') and \\\n    instance.event.record_type.name.endswith(\'__report\'):\n    with connection.cursor() as c:\n        sql = \'update events set event_expense = %s where id = %s\'\n        c.execute(sql, (expenses, instance.event.id))\n\n        sql2 = \"update events set text_20 =concat(truncate(ABS({0} - event_budget)/event_budget *100,2),\'%\') where id = {1}\".format(\n            expenses, instance.event.id)\n        c.execute(sql2)', '', '0', '1', '2019-06-24 11:08:42', '1', '2019-08-05 02:59:23', 'post_save', '1', 'custom', 'event_budget', '1');
INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('i0052552-e0e1-11e8-b6c8-02f90e0f46f4', '3f49c30f-5d59-11e6-a130-5cc5d4d378cb', '活动更新时更新总费用总预算-计划转报销', '活动更新时更新总费用总预算-计划转报销', 'trigger', 'from django.db import connection\nspeaker_expense = 0\ntotal_expense = round(sum(instance.eventexpenses_set.filter(deleted=0, total_expense__isnull=False,\n                 speaker_id__isnull=True).values_list(\'total_expense\', flat=True)))\nspeaker_expense = round(sum(instance.eventspeakers_set.filter(deleted=0, speaker_expense__isnull=False).values_list(\n    \'speaker_expense\', flat=True)))\n\nexpenses =total_expense + speaker_expense\n\nif (instance.state.name == u\'save\'or instance.state.name == u\'rejected\') and \\\n    not instance.record_type.name.endswith(\'__report\'):\n    with connection.cursor() as c1:\n        sql = \'update events set event_budget = %s where id = %s\'\n        c1.execute(sql, (expenses, instance.id))\nelif (instance.state.name == u\'save\'or instance.state.name == u\'rejected\') and \\\n    instance.record_type.name.endswith(\'__report\'):\n    with connection.cursor() as c1:\n        sql = \'update events set event_expense = %s where id = %s\'\n        c1.execute(sql, (expenses, instance.id))\n\n        sql2 = \"update events set text_20 =concat(truncate(ABS({0} - event_budget)/event_budget *100,2),\'%\') where id = {1}\".format(\n            expenses, instance.id)\n        c1.execute(sql2)', '', '0', '1', '2019-06-24 11:08:42', '1', '2019-08-05 02:59:23', 'post_save_page', '1', 'custom', 'event_expense_turn', '1');
