INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('a8da3e74-d8b3-40d6-9528-8637ce0774b0', '3f49c30f-5d59-11e6-a130-5cc5d4d378cb', '其他参会人转DCR', 'Change_to_DCR', 'trigger', 'from orion.common.user import get_user\nfrom orionbase.common.orion_enum import  approval_actions\nfrom orion.approval.approval import batch_approval_process\nfrom orionbase.common import models\nfrom orion.common.user import get_current_user\nfrom django.db import models as djm\n\nevents = models.Events.objects.filter(deleted=0, id=instance.id)\nevent = events[0] if events else None\nstate_name = event.state.name if event else \'\'\nif state_name != instance.state.name and instance.state.name == \'approved\' and instance.record_type.name.endswith(\'report\'):\n    record_type = models.ObjectRecordTypes.objects.get(object__name=\'dcr\', name=\'add_new_account\')\n    state = models.ObjectStates.objects.get(object__name=\'dcr\', name=\'draft\')\n    conditions = djm.Q(dcr_id__isnull=True) & djm.Q(deleted=0)\n    from orion.customsetting import get_setting\n    enable_child_event_setting = get_setting(\'event_enable_child_event\',None)\n    if enable_child_event_setting:\n        if event.parent:\n            conditions &= djm.Q(event_id=event.parent_id) & djm.Q(owner=event.owner)\n        else:\n            attendee_event_id = event.id\n            conditions &= djm.Q(event_id=attendee_event_id)\n            owner_ids = models.Events.advance_objects.filter(parent_id=attendee_event_id).values_list(\'owner_id\', flat=True)\n            if owner_ids:\n                conditions&= ~djm.Q(owner_id__in=owner_ids)\n    else:\n        conditions=djm.Q(event_id=event.id) & djm.Q(deleted=0)\n    event_professionals = models.EventProfessionals.objects.filter(conditions)\n    owner_users = {}\n    approvals = []\n    for professional_one in event_professionals:\n        owner_user_one = owner_users.get(professional_one.owner_id)\n        if not owner_user_one:\n            owner_user_one = get_user(professional_one.owner_id)\n            owner_users[professional_one.owner_id] = owner_user_one\n\n        record = models.DCRs()\n        record.__dict__.update(professional_one.__dict__)\n        record.deleted = 0\n        record.record_type = record_type\n        record.state_id = state.id\n        record.position_id = owner_user_one.current_position.id\n        record.id = None\n        record.save(force_insert=True)\n\n        professional_one.dcr_id = record.id\n        professional_one.save()\n\n        action = {\'action\': approval_actions.submit_for_approval, \'ignore_owner\': True}\n        approval = {}\n        approval[\'object_name\'] = \'dcr\'\n        approval[\'record_id\'] = record.id\n        approval[\'action\'] = action\n        approval[\'record\'] = record\n        approvals.append(approval)\n    approval_processor = batch_approval_process.apply_async([approvals, get_current_user().user_id], countdown=5)', '', '0', '1', '2019-06-24 11:08:42', '1', '2019-07-10 03:52:56', 'pre_save', '1', 'custom', 'Change_to_DCR', '1');
